package main

import (
	"encoding/gob"
	"fmt"
	"os"
	"path/filepath"
	"sync"
	"time"
)

type Session struct {
	ID          string
	UserID      int
	Preferences map[string]string
	Permissions []string
	CreatedAt   time.Time
	LastAccess  time.Time
}

type SessionManager struct {
	sessions    map[string]*Session
	mu          sync.RWMutex
	storageDir  string
	maxAge      time.Duration
}

func NewSessionManager(storageDir string, maxAge time.Duration) (*SessionManager, error) {
	if err := os.MkdirAll(storageDir, 0755); err != nil {
		return nil, err
	}

	sm := &SessionManager{
		sessions:   make(map[string]*Session),
		storageDir: storageDir,
		maxAge:     maxAge,
	}

	if err := sm.loadAllSessions(); err != nil {
		return nil, err
	}

	return sm, nil
}

func (sm *SessionManager) CreateSession(sessionID string, userID int, preferences map[string]string, permissions []string) (*Session, error) {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	session := &Session{
		ID:          sessionID,
		UserID:      userID,
		Preferences: preferences,
		Permissions: permissions,
		CreatedAt:   time.Now(),
		LastAccess:  time.Now(),
	}

	sm.sessions[sessionID] = session

	if err := sm.saveSessionToDisk(session); err != nil {
		delete(sm.sessions, sessionID)
		return nil, err
	}

	return session, nil
}

func (sm *SessionManager) GetSession(sessionID string) (*Session, error) {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	session, exists := sm.sessions[sessionID]
	if !exists {
		session, err := sm.loadSessionFromDisk(sessionID)
		if err != nil {
			return nil, fmt.Errorf("session not found: %s", sessionID)
		}
		sm.sessions[sessionID] = session
	}

	if time.Since(session.LastAccess) > sm.maxAge {
		sm.deleteSessionInternal(sessionID)
		return nil, fmt.Errorf("session expired: %s", sessionID)
	}

	session.LastAccess = time.Now()
	sm.saveSessionToDisk(session)

	return session, nil
}

func (sm *SessionManager) UpdateSession(sessionID string, preferences map[string]string, permissions []string) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	session, exists := sm.sessions[sessionID]
	if !exists {
		return fmt.Errorf("session not found: %s", sessionID)
	}

	if preferences != nil {
		session.Preferences = preferences
	}
	if permissions != nil {
		session.Permissions = permissions
	}
	session.LastAccess = time.Now()

	return sm.saveSessionToDisk(session)
}

func (sm *SessionManager) DeleteSession(sessionID string) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	return sm.deleteSessionInternal(sessionID)
}

func (sm *SessionManager) deleteSessionInternal(sessionID string) error {
	delete(sm.sessions, sessionID)

	filePath := sm.getSessionFilePath(sessionID)
	if err := os.Remove(filePath); err != nil && !os.IsNotExist(err) {
		return err
	}

	return nil
}

func (sm *SessionManager) saveSessionToDisk(session *Session) error {
	filePath := sm.getSessionFilePath(session.ID)

	file, err := os.Create(filePath)
	if err != nil {
		return err
	}
	defer file.Close()

	encoder := gob.NewEncoder(file)
	return encoder.Encode(session)
}

func (sm *SessionManager) loadSessionFromDisk(sessionID string) (*Session, error) {
	filePath := sm.getSessionFilePath(sessionID)

	file, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	var session Session
	decoder := gob.NewDecoder(file)
	if err := decoder.Decode(&session); err != nil {
		return nil, err
	}

	return &session, nil
}

func (sm *SessionManager) loadAllSessions() error {
	files, err := filepath.Glob(filepath.Join(sm.storageDir, "*.gob"))
	if err != nil {
		return err
	}

	for _, file := range files {
		sessionID := filepath.Base(file)
		sessionID = sessionID[:len(sessionID)-4]

		session, err := sm.loadSessionFromDisk(sessionID)
		if err != nil {
			continue
		}

		if time.Since(session.LastAccess) <= sm.maxAge {
			sm.sessions[sessionID] = session
		} else {
			os.Remove(file)
		}
	}

	return nil
}

func (sm *SessionManager) getSessionFilePath(sessionID string) string {
	return filepath.Join(sm.storageDir, sessionID+".gob")
}

func (sm *SessionManager) CleanupExpiredSessions() int {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	count := 0
	for sessionID, session := range sm.sessions {
		if time.Since(session.LastAccess) > sm.maxAge {
			sm.deleteSessionInternal(sessionID)
			count++
		}
	}

	return count
}

